// Extract the post idea and sender info from Telegram message
const msg = $json.message || $json.edited_message || {};
const text = msg.text || '';
const chatId = String(msg.chat?.id || '');
const username = msg.from?.first_name || msg.from?.username || 'عزيزي';

// Strip bot commands like /blog /post /write
const idea = text.replace(/^\/\w+\s*/,'').trim();

// Reject empty messages
if (!idea) {
  return [{json:{ skip: true, chatId, username, idea:'' }}];
}

return [{json:{ idea, chatId, username, skip: false }}];

// Parse the AI response and structure it for the publisher workflow
const aiText = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';
const chatId = $('Code: Extract Idea & Sender').first().json.chatId;

let post;
try {
  // Handle response with or without code fences
  const clean = aiText.replace(/^```(?:json)?\n?/,'').replace(/\n?```$/,'').trim();
  post = JSON.parse(clean);
} catch(e) {
  // Try to extract JSON object from response
  const match = aiText.match(/\{[\s\S]*\}/);
  if (match) { post = JSON.parse(match[0]); }
  else { throw new Error('AI did not return valid JSON: ' + aiText.substring(0,200)); }
}

// Auto-generate slug if missing
if (!post.slug) {
  post.slug = (post.title_en||'post').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
}

// Add metadata
post.date = new Date().toISOString().split('T')[0];
post.author = 'TechServJo Team';
post.chatId = chatId;

return [{json: post}];

// Check publisher response and prepare final message
const result = $input.first().json;
const post = $('Code: Parse AI Response').first().json;
const chatId = post.chatId;

if (result.success) {
  return [{json:{
    chatId,
    success: true,
    message: `✅ *تم نشر المقال بنجاح!*\n\n📰 *${post.title_ar}*\n🔗 ${result.url}\n\n⏱ سيكون متاحاً على الموقع خلال ~2 دقيقة`,
    url: result.url
  }}];
} else {
  return [{json:{
    chatId,
    success: false,
    message: `❌ *حدث خطأ أثناء النشر*\n\n${result.error || 'Unknown error'}\n\nحاول مرة أخرى أو تواصل مع المطور.`
  }}];
}
